import { useState } from 'react'
import { Container, Title, TextInput, Stack, Card, Text, Group, Badge, Loader } from '@mantine/core'
import { Search as SearchIcon } from 'lucide-react'
import { graphql } from 'gql.tada'
import { useQuery } from '@/lib/graphql'

interface SearchItem {
  id: string
  type: string
  title: string | null
  contentText: string | null
  tags: string[]
  source: string
  sourceUrl: string | null
  capturedAt: string
}

interface SearchData {
  search: {
    items: SearchItem[]
    total: number
    hasMore: boolean
  }
}

const SearchQuery = graphql(`
  query Search($query: String!, $limit: Int) {
    search(query: $query, limit: $limit) {
      items {
        id
        type
        title
        contentText
        tags
        source
        sourceUrl
        capturedAt
      }
      total
      hasMore
    }
  }
`)

function formatDate(dateStr: string): string {
  return new Date(dateStr).toLocaleDateString()
}

export function Search() {
  const [query, setQuery] = useState('')
  const [submitted, setSubmitted] = useState('')

  const [result] = useQuery<SearchData>({
    query: SearchQuery,
    variables: { query: submitted, limit: 20 },
    pause: !submitted,
  })

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    setSubmitted(query.trim())
  }

  return (
    <Container size="md" py="xl">
      <Stack gap="lg">
        <Title order={2}>Search</Title>

        <form onSubmit={handleSubmit}>
          <TextInput
            placeholder="Search your knowledge base..."
            leftSection={<SearchIcon size={16} />}
            value={query}
            onChange={(e) => setQuery(e.currentTarget.value)}
            size="md"
          />
        </form>

        {result.fetching && <Loader size="sm" />}

        {result.error && (
          <Text c="red" fz="sm">
            {result.error.message}
          </Text>
        )}

        {result.data && (
          <Stack gap="sm">
            <Text fz="sm" c="dimmed">
              {result.data.search.total} result{result.data.search.total !== 1 ? 's' : ''}
            </Text>

            {result.data.search.items.map((item) => (
              <Card key={item.id} shadow="xs" padding="md" radius="md" withBorder>
                <Group justify="space-between" mb="xs">
                  <Text fw={600}>{item.title ?? 'Untitled'}</Text>
                  <Badge size="sm" variant="light">
                    {item.type}
                  </Badge>
                </Group>
                {item.contentText && (
                  <Text fz="sm" c="dimmed" lineClamp={2}>
                    {item.contentText}
                  </Text>
                )}
                <Group gap="xs" mt="xs">
                  {item.tags.map((tag) => (
                    <Badge key={tag} size="xs" variant="outline">
                      {tag}
                    </Badge>
                  ))}
                  <Text fz="xs" c="dimmed" ml="auto">
                    {formatDate(item.capturedAt)}
                  </Text>
                </Group>
              </Card>
            ))}
          </Stack>
        )}

        {submitted && !result.fetching && result.data?.search.total === 0 && (
          <Text c="dimmed" ta="center" py="xl">
            No results found.
          </Text>
        )}
      </Stack>
    </Container>
  )
}

import { useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import {
  Group,
  Burger,
  Drawer,
  Stack,
  Button,
  Text,
  Menu,
  UnstyledButton,
  Avatar,
} from '@mantine/core'
import { useDisclosure } from '@mantine/hooks'
import { Anchor as AnchorIcon, Search, Plus, LogOut, User } from 'lucide-react'
import { useAuthStore } from '@/stores/authStore'

const NAV_LINKS = [
  { label: 'Home', to: '/' },
  { label: 'Search', to: '/search' },
  { label: 'Capture', to: '/capture' },
]

export function Header() {
  const [opened, { toggle, close }] = useDisclosure(false)
  const token = useAuthStore((s) => s.token)
  const user = useAuthStore((s) => s.user)
  const logout = useAuthStore((s) => s.logout)
  const navigate = useNavigate()
  const [userMenuOpened, setUserMenuOpened] = useState(false)

  return (
    <header
      style={{
        position: 'sticky',
        top: 0,
        zIndex: 100,
        backgroundColor: 'var(--mantine-color-brand-6)',
        padding: '0.75rem 1.5rem',
      }}
    >
      <Group justify="space-between">
        <Group gap="xs">
          <AnchorIcon size={24} color="white" />
          <Text
            component={Link}
            to="/"
            fw={700}
            fz="lg"
            c="white"
            style={{ textDecoration: 'none' }}
          >
            Flotsam
          </Text>
        </Group>

        {/* Desktop nav */}
        <Group gap="md" visibleFrom="sm">
          {NAV_LINKS.map((link) => (
            <Text
              key={link.to}
              component={Link}
              to={link.to}
              c="white"
              fz="sm"
              fw={500}
              style={{ textDecoration: 'none' }}
            >
              {link.label}
            </Text>
          ))}

          {token ? (
            <Menu
              opened={userMenuOpened}
              onChange={setUserMenuOpened}
              position="bottom-end"
              withinPortal
            >
              <Menu.Target>
                <UnstyledButton>
                  <Avatar size="sm" radius="xl" color="accent">
                    {user?.displayName?.[0] ?? user?.email?.[0] ?? 'U'}
                  </Avatar>
                </UnstyledButton>
              </Menu.Target>
              <Menu.Dropdown>
                <Menu.Item leftSection={<User size={14} />} disabled>
                  {user?.email ?? 'Account'}
                </Menu.Item>
                <Menu.Divider />
                <Menu.Item leftSection={<LogOut size={14} />} onClick={logout}>
                  Logout
                </Menu.Item>
              </Menu.Dropdown>
            </Menu>
          ) : (
            <Button
              variant="white"
              size="xs"
              onClick={() => navigate('/login')}
            >
              Login
            </Button>
          )}
        </Group>

        {/* Mobile burger */}
        <Burger
          opened={opened}
          onClick={toggle}
          hiddenFrom="sm"
          color="white"
          size="sm"
        />
      </Group>

      {/* Mobile drawer */}
      <Drawer opened={opened} onClose={close} size="xs" title="Menu">
        <Stack gap="md">
          {NAV_LINKS.map((link) => (
            <Text
              key={link.to}
              component={Link}
              to={link.to}
              fz="lg"
              onClick={close}
              style={{ textDecoration: 'none' }}
            >
              {link.label}
            </Text>
          ))}
          {token ? (
            <Button
              variant="subtle"
              leftSection={<LogOut size={16} />}
              onClick={() => {
                logout()
                close()
              }}
            >
              Logout
            </Button>
          ) : (
            <>
              <Button
                leftSection={<Search size={16} />}
                variant="light"
                onClick={() => {
                  navigate('/login')
                  close()
                }}
              >
                Login
              </Button>
              <Button
                leftSection={<Plus size={16} />}
                variant="light"
                onClick={() => {
                  navigate('/register')
                  close()
                }}
              >
                Register
              </Button>
            </>
          )}
        </Stack>
      </Drawer>
    </header>
  )
}

/**
 * Strict GraphQL utilities — re-exports urql hooks with types that reject raw strings.
 *
 * Import useQuery/useMutation from here instead of 'urql'. Raw string queries
 * bypass gql.tada's compile-time schema validation.
 *
 * Usage:
 *   import { graphql } from 'gql.tada'
 *   import { useQuery, useMutation } from '@/lib/graphql'
 *
 *   const MyQuery = graphql(`query MyQuery { ... }`)
 *   const [result] = useQuery({ query: MyQuery })
 */

import {
  useQuery as _useQuery,
  useMutation as _useMutation,
  type UseQueryResponse,
  type UseMutationResponse,
  type AnyVariables,
  type OperationContext,
  type RequestPolicy,
} from 'urql'

interface ParsedDocument {
  readonly kind: string
  readonly definitions: readonly unknown[]
}

interface StrictQueryArgs<Variables extends AnyVariables = AnyVariables> {
  query: ParsedDocument
  variables?: Variables
  requestPolicy?: RequestPolicy
  context?: Partial<OperationContext>
  pause?: boolean
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function useQuery<Data = any, Variables extends AnyVariables = AnyVariables>(
  args: StrictQueryArgs<Variables>,
): UseQueryResponse<Data, Variables> {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return _useQuery(args as any)
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function useMutation<Data = any, Variables extends AnyVariables = AnyVariables>(
  query: ParsedDocument,
): UseMutationResponse<Data, Variables> {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  return _useMutation(query as any)
}

