import { useState } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import {
  Container,
  Title,
  Text,
  Group,
  Badge,
  Stack,
  Button,
  Card,
  TagsInput,
  Loader,
  Anchor,
  Box,
} from '@mantine/core'
import { ArrowLeft, ExternalLink } from 'lucide-react'
import { graphql } from 'gql.tada'
import { useQuery, useMutation } from '@/lib/graphql'

interface ItemData {
  item: {
    id: string
    type: string
    status: string
    sensitivity: string
    title: string | null
    contentText: string | null
    contentUrl: string | null
    tags: string[]
    metadata: unknown
    autoMetadata: unknown
    source: string
    sourceUrl: string | null
    createdAt: string
    updatedAt: string
    capturedAt: string
  } | null
}

interface TagItemData {
  tagItem: {
    id: string
    tags: string[]
  }
}

const ItemQuery = graphql(`
  query Item($id: ID!) {
    item(id: $id) {
      id
      type
      status
      sensitivity
      title
      contentText
      contentUrl
      tags
      metadata
      autoMetadata
      source
      sourceUrl
      createdAt
      updatedAt
      capturedAt
    }
  }
`)

const TagItemMutation = graphql(`
  mutation TagItem($id: ID!, $tags: [String!]!) {
    tagItem(id: $id, tags: $tags) {
      id
      tags
    }
  }
`)

const TYPE_COLORS: Record<string, string> = {
  BOOKMARK: 'blue',
  TEXT_NOTE: 'green',
  VOICE_NOTE: 'orange',
  DRIVE_DOC: 'violet',
  HIGHLIGHT: 'yellow',
  FILE: 'gray',
}

const STATUS_COLORS: Record<string, string> = {
  PENDING: 'yellow',
  PROCESSING: 'blue',
  READY: 'green',
  ERROR: 'red',
}

function formatType(type: string): string {
  return type.replace(/_/g, ' ').toLowerCase()
}

function formatDate(dateStr: string): string {
  return new Date(dateStr).toLocaleString()
}

export function ItemDetail() {
  const { id } = useParams<{ id: string }>()
  const navigate = useNavigate()
  const [editingTags, setEditingTags] = useState(false)
  const [tagValues, setTagValues] = useState<string[]>([])

  const [result] = useQuery<ItemData>({
    query: ItemQuery,
    variables: { id: id! },
    pause: !id,
  })

  const [tagResult, executeMutation] = useMutation<TagItemData>(TagItemMutation)

  const item = result.data?.item

  function startEditTags() {
    if (item) {
      setTagValues([...item.tags])
      setEditingTags(true)
    }
  }

  async function saveTags() {
    if (!item) return
    await executeMutation({ id: item.id, tags: tagValues })
    setEditingTags(false)
  }

  if (result.fetching) {
    return (
      <Container size="md" py="xl">
        <Loader size="sm" />
      </Container>
    )
  }

  if (result.error) {
    return (
      <Container size="md" py="xl">
        <Text c="red">{result.error.message}</Text>
      </Container>
    )
  }

  if (!item) {
    return (
      <Container size="md" py="xl">
        <Text c="dimmed">Item not found.</Text>
      </Container>
    )
  }

  return (
    <Container size="md" py="xl">
      <Stack gap="lg">
        {/* Back navigation */}
        <Button
          variant="subtle"
          leftSection={<ArrowLeft size={16} />}
          onClick={() => navigate(-1)}
          style={{ alignSelf: 'flex-start' }}
          size="sm"
        >
          Back
        </Button>

        {/* Header */}
        <Group justify="space-between" align="flex-start">
          <Title order={2} style={{ flex: 1 }}>
            {item.title ?? 'Untitled'}
          </Title>
          <Group gap="xs">
            <Badge color={TYPE_COLORS[item.type] ?? 'gray'} variant="light">
              {formatType(item.type)}
            </Badge>
            <Badge color={STATUS_COLORS[item.status] ?? 'gray'} variant="dot">
              {item.status.toLowerCase()}
            </Badge>
          </Group>
        </Group>

        {/* Source URL for bookmarks */}
        {item.sourceUrl && (
          <Anchor href={item.sourceUrl} target="_blank" fz="sm">
            <Group gap={4}>
              <ExternalLink size={14} />
              {item.sourceUrl}
            </Group>
          </Anchor>
        )}

        {/* Content */}
        {item.contentText && (
          <Card padding="md" radius="md" withBorder>
            <Text fz="sm" style={{ whiteSpace: 'pre-wrap' }}>
              {item.contentText}
            </Text>
          </Card>
        )}

        {/* Tags */}
        <Box>
          <Group justify="space-between" mb="xs">
            <Text fw={600} fz="sm">
              Tags
            </Text>
            {!editingTags ? (
              <Button variant="subtle" size="xs" onClick={startEditTags}>
                Edit
              </Button>
            ) : (
              <Group gap="xs">
                <Button
                  variant="subtle"
                  size="xs"
                  onClick={() => setEditingTags(false)}
                >
                  Cancel
                </Button>
                <Button
                  size="xs"
                  onClick={saveTags}
                  loading={tagResult.fetching}
                >
                  Save
                </Button>
              </Group>
            )}
          </Group>
          {editingTags ? (
            <TagsInput
              value={tagValues}
              onChange={setTagValues}
              placeholder="Add tags..."
            />
          ) : (
            <Group gap="xs">
              {item.tags.length > 0 ? (
                item.tags.map((tag) => (
                  <Badge key={tag} variant="outline">
                    {tag}
                  </Badge>
                ))
              ) : (
                <Text fz="sm" c="dimmed">
                  No tags
                </Text>
              )}
            </Group>
          )}
        </Box>

        {/* Metadata */}
        <Card padding="md" radius="md" withBorder>
          <Stack gap="xs">
            <Group gap="lg">
              <Box>
                <Text fz="xs" c="dimmed">Source</Text>
                <Text fz="sm">{item.source}</Text>
              </Box>
              <Box>
                <Text fz="xs" c="dimmed">Sensitivity</Text>
                <Text fz="sm">{item.sensitivity.toLowerCase()}</Text>
              </Box>
            </Group>
            <Group gap="lg">
              <Box>
                <Text fz="xs" c="dimmed">Captured</Text>
                <Text fz="sm">{formatDate(item.capturedAt)}</Text>
              </Box>
              <Box>
                <Text fz="xs" c="dimmed">Updated</Text>
                <Text fz="sm">{formatDate(item.updatedAt)}</Text>
              </Box>
            </Group>
          </Stack>
        </Card>
      </Stack>
    </Container>
  )
}

