const SORT_OPTIONS = [
  { value: 'CAPTURED_AT:DESC', label: 'Newest first' },
  { value: 'CAPTURED_AT:ASC', label: 'Oldest first' },
  { value: 'UPDATED_AT:DESC', label: 'Recently updated' },
  { value: 'TITLE:ASC', label: 'Title A-Z' },
  { value: 'TITLE:DESC', label: 'Title Z-A' },
]

const PAGE_SIZE = 20

export function Browse() {
  const [selectedTypes, setSelectedTypes] = useState<string[]>([])
  const [sortValue, setSortValue] = useState('CAPTURED_AT:DESC')
  const [viewMode, setViewMode] = useState('grid')
  const [offset, setOffset] = useState(0)

  const filter = useMemo(() => {
    if (selectedTypes.length > 0) return { types: selectedTypes }
    return undefined
  }, [selectedTypes])

  const sort = useMemo(() => {
    const [field, direction] = sortValue.split(':')
    return { field, direction }
  }, [sortValue])

  const [result] = useQuery<ItemsData>({
    query: ItemsQuery,
    variables: { filter, limit: PAGE_SIZE, offset, sort },
  })

  const items = result.data?.items.items ?? []
  const total = result.data?.items.total ?? 0
  const hasMore = result.data?.items.hasMore ?? false

  function handleTypeChange(types: string[]) {
    setSelectedTypes(types)
    setOffset(0)
  }

  function handleSortChange(value: string | null) {
    if (value) {
      setSortValue(value)
      setOffset(0)
    }
  }

  return (
    <Container size="lg" py="xl">
      <Stack gap="lg">
        <Group justify="space-between">
          <Title order={2}>Browse</Title>
          <SegmentedControl
            value={viewMode}
            onChange={setViewMode}
            data={[
              { value: 'grid', label: <LayoutGrid size={16} /> },
              { value: 'list', label: <List size={16} /> },
            ]}
            size="xs"
          />
        </Group>

        {/* Filters row */}
        <Group justify="space-between" align="flex-end">
          <Chip.Group multiple value={selectedTypes} onChange={handleTypeChange}>
            <Group gap="xs">
              {TYPE_OPTIONS.map((opt) => (
                <Chip key={opt.value} value={opt.value} size="xs" variant="outline">
                  {opt.label}
                </Chip>
              ))}
            </Group>
          </Chip.Group>

          <Select
            value={sortValue}
            onChange={handleSortChange}
            data={SORT_OPTIONS}
            size="xs"
            w={180}
          />
        </Group>

        {result.fetching && <Loader size="sm" />}

        {result.error && (
          <Text c="red" fz="sm">
            {result.error.message}
          </Text>
        )}

        {result.data && (
          <Stack gap="md">
            <Text fz="sm" c="dimmed">
              Showing {offset + 1}–{Math.min(offset + PAGE_SIZE, total)} of {total}
            </Text>

            {items.length === 0 ? (
              <Text c="dimmed" ta="center" py="xl">
                No items found.
              </Text>
            ) : viewMode === 'grid' ? (
              <SimpleGrid cols={{ base: 1, sm: 2 }} spacing="md">
                {items.map((item) => (
                  <ItemCard key={item.id} item={item} />
                ))}
              </SimpleGrid>
            ) : (
              <Stack gap="sm">
                {items.map((item) => (
                  <ItemCard key={item.id} item={item} compact />
                ))}
              </Stack>
            )}

            {/* Pagination */}
            {total > PAGE_SIZE && (
              <Group justify="center" gap="md">
                <Button
                  variant="subtle"
                  size="sm"
                  disabled={offset === 0}
                  onClick={() => setOffset((prev) => Math.max(0, prev - PAGE_SIZE))}
                >
                  Previous
                </Button>
                <Text fz="sm" c="dimmed">
                  Page {Math.floor(offset / PAGE_SIZE) + 1} of {Math.ceil(total / PAGE_SIZE)}
                </Text>
                <Button
                  variant="subtle"
                  size="sm"
                  disabled={!hasMore}
                  onClick={() => setOffset((prev) => prev + PAGE_SIZE)}
                >
                  Next
                </Button>
              </Group>
            )}
          </Stack>
        )}
      </Stack>
    </Container>
  )
}

