import { screen } from '@testing-library/react'
import { MemoryRouter, Route, Routes } from 'react-router-dom'
import { MantineProvider } from '@mantine/core'
import { render } from '@testing-library/react'
import { Provider as UrqlProvider } from 'urql'
import { theme } from '@/theme'
import { ItemDetail } from './ItemDetail'
import { createMockClient } from '@/test/mocks'

function renderItemDetail(id = 'test-id') {
  const mockClient = createMockClient()
  return render(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    <UrqlProvider value={mockClient as any}>
      <MantineProvider theme={theme}>
        <MemoryRouter initialEntries={[`/items/${id}`]}>
          <Routes>
            <Route path="/items/:id" element={<ItemDetail />} />
          </Routes>
        </MemoryRouter>
      </MantineProvider>
    </UrqlProvider>,
  )
}

describe('ItemDetail', () => {
  it('renders the back button', () => {
    renderItemDetail()
    expect(screen.getByText('Back')).toBeInTheDocument()
  })

  it('renders loading state initially', () => {
    renderItemDetail()
    // With mock client, no data is returned so it shows loading or not found
    // The component shows a Loader when fetching
    expect(document.querySelector('[class*="loader"], [class*="Loader"]') || screen.queryByText('Item not found.')).toBeTruthy()
  })
})

