import { describe, it, expect } from 'vitest'
import { screen } from '@testing-library/react'
import { MemoryRouter, Route, Routes } from 'react-router-dom'
import { MantineProvider } from '@mantine/core'
import { render } from '@testing-library/react'
import { Provider as UrqlProvider } from 'urql'
import { theme } from '@/theme'
import { ItemDetail } from './ItemDetail'
import { createMockClient } from '@/test/mocks'

function renderItemDetail(id = 'test-id') {
  const mockClient = createMockClient()
  return render(
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    <UrqlProvider value={mockClient as any}>
      <MantineProvider theme={theme}>
        <MemoryRouter initialEntries={[`/items/${id}`]}>
          <Routes>
            <Route path="/items/:id" element={<ItemDetail />} />
          </Routes>
        </MemoryRouter>
      </MantineProvider>
    </UrqlProvider>,
  )
}

describe('ItemDetail', () => {
  it('renders without crashing', () => {
    renderItemDetail()
    // With mock client, component renders in loading or not-found state
    expect(document.querySelector('.mantine-Container-root')).toBeTruthy()
  })

  it('shows not found when no data returned', () => {
    renderItemDetail()
    // Mock client doesn't return data, so eventually shows not found or loading
    const notFound = screen.queryByText('Item not found.')
    const loader = document.querySelector('.mantine-Loader-root')
    // One of these states should be present
    expect(notFound || loader).toBeTruthy()
  })
})

